import{_ as e,b as a,e as o,al as l}from"./chunks/framework.tsjOpNIE.js";const u=JSON.parse('{"title":"React注意点","description":"","frontmatter":{},"headers":[],"relativePath":"frameworks/react/importantInfo.md","filePath":"frameworks/react/importantInfo.md","lastUpdated":1773738924000}'),r={name:"frameworks/react/importantInfo.md"};function i(d,t,c,n,s,f){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="react注意点" tabindex="-1">React注意点 <a class="header-anchor" href="#react注意点" aria-label="Permalink to &quot;React注意点&quot;">​</a></h1><h2 id="_1-组件导入和导出" tabindex="-1">1. 组件导入和导出 <a class="header-anchor" href="#_1-组件导入和导出" aria-label="Permalink to &quot;1. 组件导入和导出&quot;">​</a></h2><table tabindex="0"><thead><tr><th>导出方式</th><th>导出语句</th><th>导入语句</th></tr></thead><tbody><tr><td><strong>默认 (Default)</strong></td><td><code>export default function Button() {}</code></td><td><code>import Button from &#39;./Button.js&#39;;</code></td></tr><tr><td><strong>具名 (Named)</strong></td><td><code>export function Button() {}</code></td><td><code>import { Button } from &#39;./Button.js&#39;;</code></td></tr></tbody></table><h2 id="_2-jsx-规则" tabindex="-1">2. JSX 规则 <a class="header-anchor" href="#_2-jsx-规则" aria-label="Permalink to &quot;2. JSX 规则&quot;">​</a></h2><ul><li><strong>只能返回一个根元素</strong>。</li><li><strong>标签必须闭合</strong>。</li><li><strong>使用驼峰式命名法</strong>给大部分属性命名。</li></ul><h2 id="_3-props-注意点" tabindex="-1">3. Props 注意点 <a class="header-anchor" href="#_3-props-注意点" aria-label="Permalink to &quot;3. Props 注意点&quot;">​</a></h2><ul><li>要传递 props，请将它们添加到 JSX，就像使用 HTML 属性一样。</li><li>要读取 props，请使用 <code>function Avatar({ person, size })</code> 解构语法。</li><li>你可以指定一个默认值，如 <code>size = 100</code>，用于缺少值或值为 <code>undefined</code> 的 props。</li><li>你可以使用 <code>&lt;Avatar {...props} /&gt;</code> JSX 展开语法转发所有 props，但不要过度使用它！</li><li>像 <code>&lt;Card&gt;&lt;Avatar /&gt;&lt;/Card&gt;</code> 这样的嵌套 JSX，将被视为 <code>Card</code> 组件的 <code>children</code> prop。</li><li><strong>Props 是只读的时间快照</strong>：每次渲染都会收到新版本的 props。</li><li><strong>你不能改变 props</strong>。当你需要交互性时，你可以设置 state。</li></ul><h2 id="_4-条件渲染" tabindex="-1">4. 条件渲染 <a class="header-anchor" href="#_4-条件渲染" aria-label="Permalink to &quot;4. 条件渲染&quot;">​</a></h2><ul><li>在 React，你可以使用 JavaScript 来控制分支逻辑。</li><li>你可以使用 <code>if</code> 语句来选择性地返回 JSX 表达式。</li><li>你可以选择性地将一些 JSX 赋值给变量，然后用大括号将其嵌入到其他 JSX 中。</li><li>在 JSX 中，<code>{cond ? &lt;A /&gt; : &lt;B /&gt;}</code> 表示 <strong>“当 <code>cond</code> 为真值时, 渲染 <code>&lt;A /&gt;</code>，否则渲染 <code>&lt;B /&gt;</code>”</strong>。</li><li>在 JSX 中，<code>{cond &amp;&amp; &lt;A /&gt;}</code> 表示 <strong>“当 <code>cond</code> 为真值时, 渲染 <code>&lt;A /&gt;</code>，否则不进行渲染”</strong>。</li></ul><h2 id="_5-渲染列表-key-的作用" tabindex="-1">5. 渲染列表 Key 的作用 <a class="header-anchor" href="#_5-渲染列表-key-的作用" aria-label="Permalink to &quot;5. 渲染列表 Key 的作用&quot;">​</a></h2><p>它使 React 能追踪这些组件，即便后者的位置或数据发生了变化，也能保存组件状态。</p><ul><li><strong>key 值在兄弟节点之间必须是唯一的。</strong> 不过不要求全局唯一，在不同的数组中可以使用相同的 key。</li><li><strong>key 值不能改变</strong>，否则就失去了使用 key 的意义！所以千万不要在渲染时动态地生成 key。</li></ul><h2 id="_6-组件需要保持纯粹" tabindex="-1">6. 组件需要保持纯粹 <a class="header-anchor" href="#_6-组件需要保持纯粹" aria-label="Permalink to &quot;6. 组件需要保持纯粹&quot;">​</a></h2><p><strong>好处</strong>：将组件按纯函数严格编写，以避免一些随着代码库的增长而出现的、令人困扰的 bug 以及不可预测的行为。</p><p>一个组件必须是纯粹的，就意味着：</p><ul><li><strong>只负责自己的任务。</strong> 它不会更改在该函数调用前就已存在的对象或变量。</li><li><strong>输入相同，则输出相同。</strong> 给定相同的输入，组件应该总是返回相同的 JSX。</li></ul><h2 id="_7-响应事件" tabindex="-1">7. 响应事件 <a class="header-anchor" href="#_7-响应事件" aria-label="Permalink to &quot;7. 响应事件&quot;">​</a></h2><ul><li>你可以通过将函数作为 prop 传递给元素（如 <code>&lt;button&gt;</code>）来处理事件。</li><li>必须传递事件处理函数，<strong>而非函数调用！</strong> 是 <code>onClick={handleClick}</code>，而不是 <code>onClick={handleClick()}</code>。</li><li>你可以单独或者内联定义事件处理函数。</li><li>事件处理函数在组件内部定义，所以它们可以访问 props。</li><li>你可以在父组件中定义一个事件处理函数，并将其作为 prop 传递给子组件。</li><li>你可以根据特定于应用程序的名称定义事件处理函数的 prop。</li><li>事件会向上传播。通过事件的第一个参数调用 <code>e.stopPropagation()</code> 来防止这种情况。</li><li>事件可能具有不需要的浏览器默认行为。调用 <code>e.preventDefault()</code> 来阻止这种情况。</li><li>从子组件显式调用事件处理函数 prop 是事件传播的另一种优秀替代方案。</li></ul><h2 id="_8-组件可以通过设置-state-具有记忆性" tabindex="-1">8. 组件可以通过设置 State 具有记忆性 <a class="header-anchor" href="#_8-组件可以通过设置-state-具有记忆性" aria-label="Permalink to &quot;8. 组件可以通过设置 State 具有记忆性&quot;">​</a></h2><ul><li>State 是组件私有的。如果你在两个地方渲染它，则每个副本都有独属于自己的 state。</li></ul><h2 id="_9-更新-state" tabindex="-1">9. 更新 State <a class="header-anchor" href="#_9-更新-state" aria-label="Permalink to &quot;9. 更新 State&quot;">​</a></h2><ul><li>设置 state 不会更改现有渲染中的变量，但会请求一次新的渲染。</li><li>React 会在事件处理函数执行完成之后处理 state 更新。这被称为<strong>批处理</strong>。</li><li>要在一个事件中多次更新某些 state，你可以使用更新函数，如 <code>setNumber(n =&gt; n + 1)</code>。</li><li>将 React 中所有的 state 都视为<strong>不可直接修改</strong>的。</li></ul><h2 id="_10-更新对象类型的-state" tabindex="-1">10. 更新对象类型的 State <a class="header-anchor" href="#_10-更新对象类型的-state" aria-label="Permalink to &quot;10. 更新对象类型的 State&quot;">​</a></h2><ul><li>当你在 state 中存放对象时，直接修改对象并不会触发重渲染，并会改变前一次渲染“快照”中 state 的值。</li><li><strong>不要直接修改一个对象</strong>，而要为它创建一个<strong>新</strong>版本，并通过把 state 设置成这个新版本来触发重新渲染。</li><li>你可以使用 <code>{...obj, something: &#39;newValue&#39;}</code> 对象展开语法来创建对象的拷贝。</li><li>对象的展开语法是浅层的：它的复制深度只有一层。</li><li>想要更新嵌套对象，你需要从你更新的位置开始，自底向上为每一层都创建新的拷贝。</li><li>想要减少重复的拷贝代码，可以使用 Immer 库。</li></ul><h2 id="_11-更新数组类型的-state" tabindex="-1">11. 更新数组类型的 State <a class="header-anchor" href="#_11-更新数组类型的-state" aria-label="Permalink to &quot;11. 更新数组类型的 State&quot;">​</a></h2><p>你可以把数组放入 state 中，但不应该直接修改它。而是创建它的一份<strong>新的拷贝</strong>，然后使用新的数组来更新状态。</p><table tabindex="0"><thead><tr><th>数组操作</th><th>推荐做法 (返回新数组) ✅</th><th>避免使用 (直接修改原数组) ❌</th></tr></thead><tbody><tr><td><strong>添加元素</strong></td><td><code>concat</code>, <code>[...arr]</code> 展开语法 (<a href="https://zh-hans.react.dev/learn/updating-arrays-in-state#adding-to-an-array" target="_blank" rel="noreferrer">参考</a>)</td><td><code>push</code>, <code>unshift</code></td></tr><tr><td><strong>删除元素</strong></td><td><code>filter</code>, <code>slice</code> (<a href="https://zh-hans.react.dev/learn/updating-arrays-in-state#removing-from-an-array" target="_blank" rel="noreferrer">参考</a>)</td><td><code>pop</code>, <code>shift</code>, <code>splice</code></td></tr><tr><td><strong>替换元素</strong></td><td><code>map</code> (<a href="https://zh-hans.react.dev/learn/updating-arrays-in-state#replacing-items-in-an-array" target="_blank" rel="noreferrer">参考</a>)</td><td><code>splice</code>, <code>arr[i] = ...</code> 赋值</td></tr><tr><td><strong>排序</strong></td><td>先将数组复制一份再操作 (<a href="https://zh-hans.react.dev/learn/updating-arrays-in-state#making-other-changes-to-an-array" target="_blank" rel="noreferrer">参考</a>)</td><td><code>reverse</code>, <code>sort</code></td></tr></tbody></table><ul><li>使用 <code>[...arr, newItem]</code> 数组展开语法来向数组中添加元素。</li><li>使用 <code>filter()</code> 和 <code>map()</code> 来创建一个经过过滤或者变换的数组。</li><li>可以使用 Immer 来保持代码简洁。</li></ul><h2 id="_12-设置-state" tabindex="-1">12. 设置 State <a class="header-anchor" href="#_12-设置-state" aria-label="Permalink to &quot;12. 设置 State&quot;">​</a></h2><p><strong>步骤一：删除任何不必要的 state 变量</strong></p><ol><li>这个 state 是否会导致矛盾？</li><li>相同的信息是否已经在另一个 state 变量中存在？</li><li>你是否可以通过另一个 state 变量的相反值得到相同的信息？</li></ol><p><strong>步骤二：连接事件处理函数去设置 state</strong></p><h2 id="_13-state-的结构" tabindex="-1">13. State 的结构 <a class="header-anchor" href="#_13-state-的结构" aria-label="Permalink to &quot;13. State 的结构&quot;">​</a></h2><ul><li><strong>合并关联的 state</strong>。如果你总是同时更新两个或更多的 state 变量，请考虑将它们合并为一个单独的 state 变量。</li><li><strong>避免互相矛盾的 state</strong>。当 state 结构中存在多个相互矛盾或“不一致”的 state 时，你就可能为此会留下隐患。</li><li><strong>避免冗余的 state</strong>。如果你能在渲染期间从组件的 props 或其现有的 state 变量中计算出一些信息，则不应将这些信息放入该组件的 state 中。</li><li><strong>避免重复的 state</strong>。当同一数据在多个 state 变量之间或在多个嵌套对象中重复时，很难保持同步。应尽可能减少重复。</li><li><strong>避免深度嵌套的 state</strong>。深度分层的 state 更新起来不是很方便。最好以扁平化方式构建 state。</li></ul><h2 id="_14-组件共享状态" tabindex="-1">14. 组件共享状态 <a class="header-anchor" href="#_14-组件共享状态" aria-label="Permalink to &quot;14. 组件共享状态&quot;">​</a></h2><ul><li>当你想要整合两个组件时，将它们的 state 移动到共同的父组件中。</li><li>然后在父组件中通过 <code>props</code> 把信息传递下去。</li><li>最后，向下传递事件处理程序，以便子组件可以改变父组件的 state。</li><li>考虑将组件视为“受控”（由 prop 驱动）或是“不受控”（由 state 驱动）是十分有益的。</li></ul><h2 id="_15-保留-state-和重置-state-状态" tabindex="-1">15. 保留 State 和重置 State 状态 <a class="header-anchor" href="#_15-保留-state-和重置-state-状态" aria-label="Permalink to &quot;15. 保留 State 和重置 State 状态&quot;">​</a></h2><ul><li><strong>保留 state 状态</strong>：<a href="https://zh-hans.react.dev/learn/preserving-and-resetting-state#same-component-at-the-same-position-preserves-state" target="_blank" rel="noreferrer">相同位置的相同组件会使得 state 被保留下来</a>。只要在相同位置渲染的是相同组件，React 就会保留状态。</li><li><strong>重置 state 状态</strong>： <ol><li>将组件渲染在不同位置。</li><li>使用 <code>key</code> 来重置 state。可以通过为一个子树指定一个不同的 key 来重置它的 state。</li></ol></li><li>state 不会被保存在 JSX 标签里。它与你在树中放置该 JSX 的位置相关联。</li><li><strong>不要嵌套组件的定义</strong>，否则你会意外地导致 state 被频繁重置。</li></ul><h2 id="_16-使用-reducer-整合状态逻辑" tabindex="-1">16. 使用 Reducer 整合状态逻辑 <a class="header-anchor" href="#_16-使用-reducer-整合状态逻辑" aria-label="Permalink to &quot;16. 使用 Reducer 整合状态逻辑&quot;">​</a></h2><ul><li>把 <code>useState</code> 转化为 <code>useReducer</code>： <ol><li>通过事件处理函数 dispatch actions；</li><li>编写一个 reducer 函数，它接受传入的 state 和一个 action，并返回一个新的 state；</li><li>使用 <code>useReducer</code> 替换 <code>useState</code>。</li></ol></li><li>Reducer 可能需要你写更多的代码，但是这有利于代码的调试和测试。</li><li><strong>Reducer 必须是纯净的</strong>。</li><li>每个 action 都描述了一个单一的用户交互。</li><li>可以使用 Immer 来帮助你在 reducer 里直接修改状态（简化代码书写）。</li></ul><h2 id="_17-跨组件传递参数-context" tabindex="-1">17. 跨组件传递参数 Context <a class="header-anchor" href="#_17-跨组件传递参数-context" aria-label="Permalink to &quot;17. 跨组件传递参数 Context&quot;">​</a></h2><ul><li>Context 使组件向其下方的整个树提供信息。</li><li><strong>传递 Context 的方法</strong>: <ol><li>通过 <code>export const MyContext = createContext(defaultValue)</code> 创建并导出 context。</li><li>在无论层级多深的任何子组件中，把 context 传递给 <code>useContext(MyContext)</code> Hook 来读取它。</li><li>在父组件中把 children 包在 <code>&lt;MyContext.Provider value={...}&gt;</code> 中来提供 context。</li></ol></li><li>Context 会穿过中间的任何组件。</li><li>Context 可以让你写出“较为通用”的组件。</li><li>在使用 context 之前，先试试传递 props 或者将 JSX 作为 <code>children</code> 传递。</li></ul><h2 id="_18-使用-reducer-和-context-结合-类似-react-redux" tabindex="-1">18. 使用 Reducer 和 Context 结合 (类似 react-redux) <a class="header-anchor" href="#_18-使用-reducer-和-context-结合-类似-react-redux" aria-label="Permalink to &quot;18. 使用 Reducer 和 Context 结合 (类似 react-redux)&quot;">​</a></h2><ul><li>你可以将 reducer 与 context 相结合，让任何组件读取和更新它的状态。</li><li><strong>为子组件提供 state 和 dispatch 函数</strong>： <ol><li>创建两个 context (一个用于 state，一个用于 dispatch 函数)。</li><li>让组件的 context 使用 reducer。</li><li>使用组件中需要读取的 context。</li></ol></li><li>你可以通过将所有传递信息的代码移动到单个文件中来进一步整理组件。 <ul><li>你可以导出一个像 <code>TasksProvider</code> 这样可以提供 context 的组件。</li><li>你也可以导出像 <code>useTasks</code> 和 <code>useTasksDispatch</code> 这样的自定义 Hook。</li></ul></li><li>你可以在你的应用程序中大量使用 context 和 reducer 的组合。</li></ul><h2 id="_19-ref-和-state-不同之处" tabindex="-1">19. Ref 和 State 不同之处 <a class="header-anchor" href="#_19-ref-和-state-不同之处" aria-label="Permalink to &quot;19. Ref 和 State 不同之处&quot;">​</a></h2><table tabindex="0"><thead><tr><th>特性</th><th>Ref</th><th>State</th></tr></thead><tbody><tr><td><strong>返回值</strong></td><td><code>useRef(initialValue)</code> 返回 <code>{ current: initialValue }</code></td><td><code>useState(initialValue)</code> 返回 state 变量的当前值和一个 state 设置函数 <code>[value, setValue]</code></td></tr><tr><td><strong>触发渲染</strong></td><td>更改时<strong>不会</strong>触发重新渲染。</td><td>更改时<strong>会</strong>触发重新渲染。</td></tr><tr><td><strong>可变性</strong></td><td><strong>可变</strong> —— 你可以在渲染过程之外修改和更新 <code>current</code> 的值。</td><td><strong>“不可变”</strong> —— 你必须使用 state 设置函数来修改 state 变量，从而排队重新渲染。</td></tr><tr><td><strong>读写时机</strong></td><td>你<strong>不应</strong>在渲染期间读取（或写入） <code>current</code> 值。</td><td>你可以随时读取 state。但是，每次渲染都有自己不变的 state <a href="https://zh-hans.react.dev/learn/state-as-a-snapshot" target="_blank" rel="noreferrer">快照</a>。</td></tr></tbody></table><h2 id="_20-ref-的用处" tabindex="-1">20. Ref 的用处 <a class="header-anchor" href="#_20-ref-的用处" aria-label="Permalink to &quot;20. Ref 的用处&quot;">​</a></h2><ul><li>存储 <a href="https://developer.mozilla.org/docs/Web/API/setTimeout" target="_blank" rel="noreferrer">timeout ID</a>。</li><li>存储和操作 <a href="https://developer.mozilla.org/docs/Web/API/Element" target="_blank" rel="noreferrer">DOM 元素</a>。</li><li>存储不需要被用来计算 JSX 的其他对象。</li><li><strong>将 ref 视为脱围机制</strong>。当你使用外部系统或浏览器 API 时，ref 很有用。如果你很大一部分应用程序逻辑和数据流都依赖于 ref，你可能需要重新考虑你的方法。</li><li><strong>不要在渲染过程中读取或写入 <code>ref.current</code>。</strong> 如果渲染过程中需要某些信息，请使用 state 代替。由于 React 不知道 <code>ref.current</code> 何时发生变化，即使在渲染时读取它也会使组件的行为难以预测。（唯一的例外是像 <code>if (!ref.current) ref.current = new Thing()</code> 这样的代码，它只在第一次渲染期间设置一次 ref。）</li><li>与 state 一样，ref 允许你在组件的重新渲染之间保留信息；与 state 不同，设置 ref 的 <code>current</code> 值不会触发重新渲染。</li><li>通常，你会将 refs 用于非破坏性操作，例如聚焦、滚动或测量 DOM 元素。</li><li>默认情况下，组件不暴露其 DOM 节点。你可以通过使用 <code>ref</code> 属性来暴露 DOM 节点。避免更改由 React 管理的 DOM 节点。</li></ul><h2 id="_21-effect" tabindex="-1">21. Effect <a class="header-anchor" href="#_21-effect" aria-label="Permalink to &quot;21. Effect&quot;">​</a></h2><ul><li>与事件不同，Effect 由渲染本身引起，而非特定的交互。</li><li>Effect 允许你将组件与某些外部系统（第三方 API、网络等）同步。</li><li>默认情况下，Effect 在每次渲染（包括初始渲染）后运行。</li><li>如果所有依赖项都与上一次渲染时相同，React 会跳过本次 Effect。</li><li>你不能“选择”依赖项，它们是由 Effect 内部的代码所决定的。</li><li>空的依赖数组 (<code>[]</code>) 对应于组件的“挂载”，即组件被添加到页面上时。</li><li>仅在严格模式下的开发环境中，React 会挂载两次组件，以对 Effect 进行压力测试。</li><li>如果你的 Effect 因为重新挂载而出现问题，那么你需要实现一个清理函数。</li><li>React 会在 Effect 再次运行之前和在组件卸载时调用你的清理函数。</li></ul><h2 id="_22-如何移除不必要的-effect" tabindex="-1">22. 如何移除不必要的 Effect <a class="header-anchor" href="#_22-如何移除不必要的-effect" aria-label="Permalink to &quot;22. 如何移除不必要的 Effect&quot;">​</a></h2><ul><li>如果你可以在渲染期间计算某些内容，则不需要使用 Effect。</li><li>想要缓存昂贵的计算，请使用 <code>useMemo</code> 而不是 <code>useEffect</code>。</li><li>想要重置整个组件树的 state，请传入不同的 <code>key</code>。</li><li>想要在 prop 变化时重置某些特定的 state，请在渲染期间处理。</li><li>组件<strong>显示</strong>时就需要执行的代码应该放在 Effect 中，否则应该放在事件处理函数中。</li><li>如果你需要更新多个组件的 state，最好在单个事件处理函数中处理。</li><li>当你尝试在不同组件中同步 state 变量时，请考虑状态提升。</li><li>你可以使用 Effect 获取数据，但你需要实现清除逻辑以避免竞态条件。</li></ul><h2 id="_23-effect-生命周期" tabindex="-1">23. Effect 生命周期 <a class="header-anchor" href="#_23-effect-生命周期" aria-label="Permalink to &quot;23. Effect 生命周期&quot;">​</a></h2><ul><li>组件可以挂载、更新和卸载。</li><li>每个 Effect 与周围组件有着独立的生命周期。</li><li>每个 Effect 描述了一个独立的同步过程，可以<strong>开始</strong>和<strong>停止</strong>。</li><li>在编写和读取 Effect 时，要独立地考虑每个 Effect（如何开始和停止同步），而不是从组件的角度思考（如何挂载、更新或卸载）。</li><li>在组件主体内声明的值是“响应式”的。</li><li>响应式值应该重新进行同步 Effect，因为它们可以随着时间的推移而发生变化。</li><li>检查工具会验证在 Effect 内部使用的所有响应式值是否都被指定为了依赖项。标记的所有错误都是合理的，总是有一种方法可以修复代码，同时不违反规则。</li></ul><h2 id="_24-effect-非响应式数据事件-effect-event" tabindex="-1">24. Effect 非响应式数据事件 Effect Event <a class="header-anchor" href="#_24-effect-非响应式数据事件-effect-event" aria-label="Permalink to &quot;24. Effect 非响应式数据事件 Effect Event&quot;">​</a></h2><ul><li>事件处理函数在响应特定交互时运行（例如提交表单，按钮点击事件）。</li><li>Effect 在需要同步的时候运行。</li><li>事件处理函数内部的逻辑是<strong>非响应式</strong>的。（手动触发的都是非响应式）</li><li>Effect 内部的逻辑是<strong>响应式</strong>的。（effect 内部逻辑都是自动触发的）</li><li>你可以将非响应式逻辑从 Effect 移到 Effect Event 中（实验性 API 如 <code>useEffectEvent</code>）。</li><li>只在 Effect 内部调用 Effect Event。</li><li>不要将 Effect Event 传给其他组件或者 Hook。</li></ul><h2 id="_25-移除-effect-依赖" tabindex="-1">25. 移除 Effect 依赖 <a class="header-anchor" href="#_25-移除-effect-依赖" aria-label="Permalink to &quot;25. 移除 Effect 依赖&quot;">​</a></h2><ul><li>依赖应始终与代码匹配。当你对依赖不满意时，你需要编辑的是代码。</li><li>抑制 linter 会导致非常混乱的错误，你应该始终避免它。要移除依赖，你需要向 linter “证明”它不是必需的。</li><li>如果某些代码是为了响应特定交互，请将该代码移至事件处理的地方。</li><li>如果 Effect 的不同部分因不同原因需要重新运行，请将其拆分为多个 Effect。</li><li>如果你想根据以前的状态更新一些状态，传递一个更新函数。</li><li>如果你想读取最新值而不“反应”它，请从 Effect 中提取出一个 Effect Event。</li><li>在 JavaScript 中，如果对象和函数是在不同时间创建的，则它们被认为是不同的。尽量避免对象和函数依赖。将它们移到组件外或 Effect 内。</li></ul><h2 id="_26-自定义-hook" tabindex="-1">26. 自定义 Hook <a class="header-anchor" href="#_26-自定义-hook" aria-label="Permalink to &quot;26. 自定义 Hook&quot;">​</a></h2><ul><li>自定义 Hook 让你可以在组件间共享逻辑。</li><li>自定义 Hook 命名必须以 <code>use</code> 开头，后面跟一个大写字母。</li><li>自定义 Hook <strong>共享的只是状态逻辑，不是状态本身</strong>。</li><li>你可以将响应值从一个 Hook 传到另一个，并且它们会保持最新。</li><li>每次组件重新渲染时，所有的 Hook 会重新运行。</li><li>自定义 Hook 的代码应该和组件代码一样保持纯粹。</li><li>把自定义 Hook 收到的事件处理函数包裹到 Effect Event。</li></ul>',60)])])}const g=e(r,[["render",i]]);export{u as __pageData,g as default};
